class Solution {
    public int makeTheIntegerZero(int num1, int num2) {
        long n1 = num1;
        long n2 = num2;
        for (int i = 0; i <= 30; i++) {
            if ((n1 - i * n2) >= i && (n1 - i * n2) >= 0 && (Long.bitCount(n1 - i * n2) <= i)) {
                return i;
            }
        }
        return -1;
    }
}
